{"command": "cd /app/data/auto-opt/utils/llvm-65863 && cat <<'CODEEOF' | python $AGENT_TOOLS_DIR/apply_code.py write llvm/lib/Analysis/InstructionSimplify.cpp 1870 1899
// Try to simplify and/or of two icmp instructions that both compare an add
// result with each of the add operands. This is an overflow check pattern
// where both compares are equivalent.
// (icmp ult/ugt (add X, Y), X) | (icmp ult/ugt (add X, Y), Y)
//     -> (icmp ult/ugt (add X, Y), X)
// (icmp uge/ule (add X, Y), X) & (icmp uge/ule (add X, Y), Y)
//     -> (icmp uge/ule (add X, Y), X)
static Value *simplifyAndOrOfICmpsWithOverflowCheck(ICmpInst *Op0,
                                                     ICmpInst *Op1,
                                                     bool IsAnd) {
  // Determine if each compare is an overflow or no-overflow check against
  // one of the add's operands. Extract the add instruction and which operand
  // of the add is being compared.
  auto MatchAddOverflowCheck = [](ICmpInst *Cmp, BinaryOperator *&Add,
                                  int &OpIdx, bool &IsOverflow) -> bool {
    Value *AddVal, *CmpOp;
    ICmpInst::Predicate Pred = Cmp->getPredicate();

    // Check both operand orders: (add X, Y) pred Z, or Z pred (add X, Y)
    if (match(Cmp, m_c_ICmp(Pred, m_Add(m_Value(), m_Value()), m_Value()))) {
      // The add could be either operand 0 or operand 1 of the icmp after
      // matching with m_c_ICmp (which handles commutation).
      // Recover which operand is the add.
      Value *Op0 = Cmp->getOperand(0);
      Value *Op1 = Cmp->getOperand(1);
      if (match(Op0, m_BinOp(Instruction::Add))) {
        AddVal = Op0;
        CmpOp = Op1;
        // Pred is canonical (add is LHS)
      } else {
        AddVal = Op1;
        CmpOp = Op0;
        // Pred was swapped by m_c_ICmp; swap it back to get canonical form
        Pred = ICmpInst::getSwappedPredicate(Pred);
      }
    } else {
      return false;
    }

    Add = cast<BinaryOperator>(AddVal);
    if (CmpOp == Add->getOperand(0)) {
      OpIdx = 0;
    } else if (CmpOp == Add->getOperand(1)) {
      OpIdx = 1;
    } else {
      return false;
    }

    // Determine if this is an overflow check (ULT) or no-overflow check (UGE)
    if (Pred == ICmpInst::ICMP_ULT) {
      IsOverflow = true;
      return true;
    }
    if (Pred == ICmpInst::ICMP_UGE) {
      IsOverflow = false;
      return true;
    }
    return false;
  };

  BinaryOperator *Add0, *Add1;
  int OpIdx0, OpIdx1;
  bool IsOverflow0, IsOverflow1;

  if (!MatchAddOverflowCheck(Op0, Add0, OpIdx0, IsOverflow0) ||
      !MatchAddOverflowCheck(Op1, Add1, OpIdx1, IsOverflow1))
    return nullptr;

  // Both must refer to the same add instruction
  if (Add0 != Add1)
    return nullptr;

  // Both must check the same condition type (overflow or no-overflow)
  if (IsOverflow0 != IsOverflow1)
    return nullptr;

  // Must check against different operands of the add
  if (OpIdx0 == OpIdx1)
    return nullptr;

  // For AND, we need no-overflow checks (UGE/ULE)
  // For OR, we need overflow checks (ULT/UGT)
  if (IsAnd == IsOverflow0)
    return nullptr;

  return Op0;
}
